    89→
    90→            <Route path='collections' element={<Collections/>}/>
    91→            <Route path='collectionCards' element={<CollectionJournals/>}/>
    92→            
    93→            {/* route for nested notifications */}
    94→            <Route path='notifications' element={<Notifications/>}>
    95→              <Route index element={<NotificationCards/>}/>
    96→              <Route path='unreadNotification' element={<UnreadNotification/>}/>
    97→            </Route>  
    98→          </Route>   
    99→
   100→          <Route path='/login' element={<LoginPage/>}/>
   101→          <Route path='/signUp' element={<SignUp/>}/>
   102→        </Routes>
   103→      </HashRouter>
   104→    </LexicalComposer>
   105→    </>
   106→  )
   107→}
   108→
   109→export default App
